package types

import (
	"context"
	"math/big"

	"github.com/smartcontractkit/chainlink-common/pkg/services"
)

const (
	ErrSettingTransactionGasLimitNotSupported = InvalidArgumentError("setting transaction gas limit is not supported")
)

// IdempotencyKey is generated by SubmitTransaction caller to prevent double sending or to track transaction status
type IdempotencyKey = string

// ExpectedSimulationFailureError defines a rule for expected simulation failures.
// When simulation of a transaction fails, these rules determine whether the
// failure is expected and the transaction should still be submitted.
type ExpectedSimulationFailureError struct {
	// ErrorString is the error message string to match against simulation failures.
	ErrorString string
}

// SimulationOptions controls transaction simulation behavior.
// When nil is passed for this parameter, the implementation uses its default simulation behavior.
// When SimulateTransaction is false, ExpectedSimulationFailureErrors is ignored.
type SimulationOptions struct {
	// SimulateTransaction controls whether the transaction should be simulated before submission.
	SimulateTransaction bool
	// ExpectedSimulationFailureErrors defines rules for expected simulation failures.
	// Only meaningful when SimulateTransaction is true.
	ExpectedSimulationFailureErrors []ExpectedSimulationFailureError
}

type ContractWriter interface {
	services.Service

	// SubmitTransaction packs and broadcasts a transaction to the underlying chain contract.
	//
	// - `args` should be any object which maps a set of method param into the contract and method specific method params.
	// - `transactionID` will be used by the underlying TXM as an idempotency key, and unique reference to track transaction attempts.
	// - `simulationOpts` controls simulation behavior. When nil, the implementation uses its default behavior.
	SubmitTransaction(ctx context.Context, contractName, method string, args any, transactionID IdempotencyKey, toAddress string, meta *TxMeta, value *big.Int, simulationOpts *SimulationOptions) error

	// GetTransactionStatus returns the current status of a transaction in the underlying chain's TXM.
	GetTransactionStatus(ctx context.Context, transactionID IdempotencyKey) (TransactionStatus, error)

	// GetFeeComponents retrieves the associated gas costs for executing a transaction.
	GetFeeComponents(ctx context.Context) (*ChainFeeComponents, error)

	// GetEstimateFee returns total cost of TX execution in the underlying chain's currency
	// The value (val) is included in the fee calculation.
	GetEstimateFee(ctx context.Context, contract, method string, args any, toAddress string, meta *TxMeta, val *big.Int) (EstimateFee, error)
}

// TxMeta contains metadata fields for a transaction.
type TxMeta struct {
	// Used for Keystone Workflows
	WorkflowExecutionID *string
	// An optional maximum gas limit for the transaction. If not set the ContractWriter implementation will be responsible for
	// setting a gas limit for the transaction.  If it is set and the ContractWriter implementation does not support setting
	// this value per transaction it will return ErrSettingTransactionGasLimitNotSupported
	GasLimit *big.Int
}

// TransactionStatus are the status we expect every TXM to support and that can be returned by StatusForUUID.
type TransactionStatus int

const (
	Unknown TransactionStatus = iota
	Pending
	Unconfirmed
	Finalized
	Failed
	Fatal
)

// ChainFeeComponents contains the different cost components of executing a transaction.
type ChainFeeComponents struct {
	// The cost of executing transaction in the chain's EVM (or the L2 environment).
	ExecutionFee *big.Int

	// The cost associated with an L2 posting a transaction's data to the L1.
	DataAvailabilityFee *big.Int
}

// Estimated total cost of TX execution in the underlying chain's currency
type EstimateFee struct {
	Fee      *big.Int
	Decimals uint32
}

type UnimplementedContractWriter struct{}

var _ ContractWriter = UnimplementedContractWriter{}

func (UnimplementedContractWriter) SubmitTransaction(ctx context.Context, contractName, method string, args any, transactionID IdempotencyKey, toAddress string, meta *TxMeta, value *big.Int, simulationOpts *SimulationOptions) error {
	return UnimplementedError("ContractWriter.SubmitTransaction unimplemented")
}

func (UnimplementedContractWriter) GetTransactionStatus(ctx context.Context, transactionID IdempotencyKey) (TransactionStatus, error) {
	return Unknown, UnimplementedError("ContractWriter.GetTransactionStatus unimplemented")
}

func (UnimplementedContractWriter) GetFeeComponents(ctx context.Context) (*ChainFeeComponents, error) {
	return nil, UnimplementedError("ContractWriter.GetFeeComponents unimplemented")
}

func (UnimplementedContractWriter) GetEstimateFee(ctx context.Context, contract, method string, args any, toAddress string, meta *TxMeta, val *big.Int) (EstimateFee, error) {
	return EstimateFee{}, UnimplementedError("ContractWriter.GetEstimateFee unimplemented")
}

func (UnimplementedContractWriter) Start(context.Context) error         { return nil }
func (UnimplementedContractWriter) Close() error                        { return nil }
func (UnimplementedContractWriter) HealthReport() map[string]error      { return nil }
func (UnimplementedContractWriter) Name() string                        { return "UnimplementedContractWriter" }
func (UnimplementedContractWriter) Ready() error                        { return nil }
